SELECT SUM(total_gallons_used) AS total_water_usage
FROM water_usage
WHERE customer_id = 1 AND billing_period BETWEEN '2023-01-01' AND '2023-12-31';

SELECT SUM(total_gallons_used) AS total_water_used
FROM water_usage
WHERE customer_id = 1;

SELECT SUM(total_gallons_used) AS total_water_used
FROM water_usage
WHERE billing_period = '2023-04-01';

SELECT SUM(total_gallons_used) AS total_water_usage
FROM water_usage
WHERE billing_period = (SELECT MAX(billing_period) FROM water_usage);

SELECT MAX(total_due) AS peak_bill
FROM billing_records
WHERE billing_period = '2023-04-01';

SELECT customer_id
FROM payment_history
WHERE payment_status = 'failed';

SELECT COUNT(DISTINCT customer_id)
  FROM payment_history
  WHERE payment_status = 'failed';

SELECT customer_id
FROM billing_records
WHERE payment_status = 'pending';
